import fs from "node:fs/promises";
import os from "node:os";
import path from "node:path";
import { fileURLToPath, pathToFileURL } from "node:url";

export const ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
export const COMMITTED_VENDOR_DIR = path.join(ROOT, "src", "dashboard", "public", "vendor");

/**
 * @param {{ root?: string, outputDir?: string, dependencyRoot?: string }} [options]
 */
export async function buildDashboardAssets(options = {}) {
  const root = options.root ?? ROOT;
  const dependencyRoot = options.dependencyRoot ?? root;
  const nodeModulesDir = path.join(dependencyRoot, "node_modules");
  const outputDir = options.outputDir ?? path.join(root, "src", "dashboard", "public", "vendor");
  const richBundlePath = path.join(outputDir, "rich-renderers.js");
  const esbuild = await import(pathToFileURL(path.join(nodeModulesDir, "esbuild", "lib", "main.js")).href);

  await fs.rm(outputDir, { recursive: true, force: true });
  await fs.mkdir(outputDir, { recursive: true });
  await esbuild.build({
    entryPoints: [path.join(root, "src", "dashboard", "vendor", "rich-entry.js")],
    bundle: true,
    format: "esm",
    platform: "browser",
    target: "es2022",
    minify: true,
    sourcemap: false,
    banner: { js: "// @ts-nocheck" },
    plugins: [resolveAssetDependencies(esbuild, dependencyRoot)],
    outfile: richBundlePath,
    logLevel: "silent"
  });
  await normalizeGeneratedText(richBundlePath);

  const katexRoot = path.join(nodeModulesDir, "katex", "dist");
  const katexCss = await fs.readFile(path.join(katexRoot, "katex.min.css"), "utf8");
  await fs.writeFile(path.join(outputDir, "katex.min.css"), rewriteKatexFontUrls(katexCss), "utf8");

  const fontSource = path.join(katexRoot, "fonts");
  const fontTarget = path.join(outputDir, "fonts");
  await fs.mkdir(fontTarget, { recursive: true });
  const fontEntries = (await fs.readdir(fontSource, { withFileTypes: true }))
    .filter((entry) => entry.isFile())
    .sort((left, right) => left.name.localeCompare(right.name));
  for (const entry of fontEntries) {
    await fs.copyFile(path.join(fontSource, entry.name), path.join(fontTarget, entry.name));
  }

  return {
    outputDir,
    fileCount: 2 + fontEntries.length
  };
}

/**
 * Rebuild assets outside the repository and compare every generated byte.
 *
 * @param {{ root?: string, committedVendorDir?: string, dependencyRoot?: string }} [options]
 */
export async function verifyDashboardAssets(options = {}) {
  const root = options.root ?? ROOT;
  const committedVendorDir = options.committedVendorDir ?? path.join(root, "src", "dashboard", "public", "vendor");
  const temporaryRoot = await fs.mkdtemp(path.join(os.tmpdir(), "ant-code-dashboard-assets-"));
  const generatedVendorDir = path.join(temporaryRoot, "vendor");

  try {
    const result = await buildDashboardAssets({
      root,
      outputDir: generatedVendorDir,
      dependencyRoot: options.dependencyRoot
    });
    await assertDashboardAssetTreesMatch(generatedVendorDir, committedVendorDir);
    return result;
  } finally {
    await fs.rm(temporaryRoot, { recursive: true, force: true });
  }
}

/**
 * @param {string} generatedDir
 * @param {string} committedDir
 */
export async function assertDashboardAssetTreesMatch(generatedDir, committedDir) {
  const generatedFiles = await listFiles(generatedDir);
  const committedFiles = await listFiles(committedDir);
  const generatedSet = new Set(generatedFiles);
  const committedSet = new Set(committedFiles);
  const missing = generatedFiles.filter((file) => !committedSet.has(file));
  const unexpected = committedFiles.filter((file) => !generatedSet.has(file));
  const changed = [];

  for (const relativePath of generatedFiles) {
    if (!committedSet.has(relativePath)) {
      continue;
    }
    const [generated, committed] = await Promise.all([
      fs.readFile(path.join(generatedDir, ...relativePath.split("/"))),
      fs.readFile(path.join(committedDir, ...relativePath.split("/")))
    ]);
    if (!generated.equals(committed)) {
      changed.push(relativePath);
    }
  }

  if (missing.length === 0 && unexpected.length === 0 && changed.length === 0) {
    return;
  }

  const details = [
    ...missing.map((file) => `missing committed asset: ${file}`),
    ...unexpected.map((file) => `unexpected committed asset: ${file}`),
    ...changed.map((file) => `stale committed asset: ${file}`)
  ];
  throw new Error([
    "Dashboard asset check failed.",
    ...details.map((detail) => `- ${detail}`),
    "Run `npm run build:dashboard-assets` and commit the regenerated assets."
  ].join("\n"));
}

/**
 * @param {string} css
 */
export function rewriteKatexFontUrls(css) {
  return css.replace(/url\(fonts\//g, "url(/assets/vendor/fonts/");
}

/**
 * Resolve top-level rich-renderer packages from an isolated dependency root.
 *
 * @param {typeof import("esbuild")} esbuild
 * @param {string} dependencyRoot
 * @returns {import("esbuild").Plugin}
 */
function resolveAssetDependencies(esbuild, dependencyRoot) {
  return {
    name: "dashboard-asset-dependencies",
    setup(buildContext) {
      buildContext.onResolve({ filter: /^(?:katex|mermaid|yaml)$/ }, async (args) => {
        if (args.pluginData?.dashboardAssetDependency) {
          return null;
        }
        return buildContext.resolve(args.path, {
          kind: args.kind,
          resolveDir: dependencyRoot,
          pluginData: { dashboardAssetDependency: true }
        });
      });
    }
  };
}

/**
 * @param {string} root
 * @param {string} [prefix]
 * @returns {Promise<string[]>}
 */
async function listFiles(root, prefix = "") {
  const directory = path.join(root, ...prefix.split("/").filter(Boolean));
  const entries = await fs.readdir(directory, { withFileTypes: true }).catch((error) => {
    if (error?.code === "ENOENT") {
      return [];
    }
    throw error;
  });
  const files = [];
  for (const entry of entries) {
    const relativePath = prefix ? `${prefix}/${entry.name}` : entry.name;
    if (entry.isDirectory()) {
      files.push(...await listFiles(root, relativePath));
    } else if (entry.isFile()) {
      files.push(relativePath);
    }
  }
  return files.sort();
}

/**
 * @param {string} filePath
 */
async function normalizeGeneratedText(filePath) {
  const text = await fs.readFile(filePath, "utf8");
  await fs.writeFile(filePath, text.replace(/[ \t]+$/gm, ""), "utf8");
}
